export const smallChopsMenu = [
  {
    id: "starter-mark",
    name: "The Starter Mark",
    price: "15,000",
    description: "The perfect introduction to Àmí flavors.",
    contents: [
      { item: "Samosas", qty: 7, icon: "🥟" },
      { item: "Spring Rolls", qty: 7, icon: "🌯" },
      { item: "Puff-Puff", qty: 15, icon: "🥯" },
      { item: "Mosa / Money Bags", qty: "10 / 5", icon: "💰" },
      { item: "Peppered Chicken", qty: 4, icon: "🍗" }
    ]
  },

  {
    id: "signature-platter",
    name: "Signature Àmí Platter",
    price: "25,000",
    description: "Premium hosting tray for small gatherings.",
    contents: [
      { item: "Samosas", qty: 10, icon: "🥟" },
      { item: "Spring Rolls", qty: 10, icon: "🌯" },
      { item: "Puff-Puff", qty: 20, icon: "🥯" },
      { item: "Mosa / Money Bags", qty: 10, icon: "💰" },
      { item: "Peppered Chicken", qty: 6, icon: "🍗" }
    ]
  },
  {
    id: "owambe-pack",
    name: "The Owambe Event Pack",
    price: "150,000",
    description: "The ultimate event solution. No stress, just luxury.",
    contents: [
      { item: "Guest Capacity", qty: "50 Persons", icon: "🎉" },
      { item: "Total Pieces", qty: "350+ Pieces", icon: "📈" }, // This looks huge compared to 10s and 20s
      { item: "Packaging", qty: "Branded Mini-Boxes", icon: "🎁" }, // Value Add!
      { item: "Delivery", qty: "Priority Event Slot", icon: "🚚" }, // Value Add!
      { item: "Dipping Sauce", qty: "Signature Àmí Dip", icon: "🏺" } // Exclusive to events
    ]
  },
  
  {
    id: "customized-luxury",
    name: "Customized Luxury",
    price: "Starts at 200,000",
    description: "Bespoke catering tailored to your specific guest list.",
    contents: [
      { item: "Guest Count", qty: "Flexible", icon: "👥" },
      { item: "Menu Selection", qty: "Bespoke", icon: "💎" },
      { item: "Consultation", qty: "Priority", icon: "📞" }
    ]
  }
];
